function i(n){return String(n||"").replace(/\D/g,"")}function l(n){return String(n||"").trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9]+/g,"-").replace(/(^-+|-+$)/g,"")}function c(n){let e=i(n);if(e.startsWith("55")&&e.length>11&&(e=e.slice(2)),e=e.slice(0,11),e.length<=2)return e?`(${e}`:"";const r=e.slice(0,2),t=e.slice(2);return t.length<=4?`(${r}) ${t}`:e.length<=10?`(${r}) ${t.slice(0,4)}-${t.slice(4)}`:`(${r}) ${t.slice(0,5)}-${t.slice(5)}`}export{c as f,l as n};
